#include <omp.h>
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <limits.h>

#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

void 
kernel_cpu(	int cores_arg,

			record *records,
			knode *knodes,
			long knodes_elem,

			int order,
			long maxheight,
			int count,

			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	int bid;
	int thid;
	int i;

	#pragma omp parallel for num_threads(cores_arg)
	for(bid = 0; bid < count; bid++){

		offset[bid] = currKnode[bid];

		for(i = 0; i < maxheight; i++){

			for(thid = 0; thid < order; thid++){

				if((knodes[currKnode[bid]].keys[thid]) <= keys[bid] && 
				   (knodes[currKnode[bid]].keys[thid+1] > keys[bid])){

					if(knodes[offset[bid]].indices[thid] < knodes_elem){
						offset[bid] = knodes[offset[bid]].indices[thid];
					}
				}
			}

			currKnode[bid] = offset[bid];
		}


		for(thid = 0; thid < order; thid++){
			if(knodes[currKnode[bid]].keys[thid] == keys[bid]){
				ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
				break;
			}
		}
	}
}

